window.DATA=[{"c": "清晨·从闹钟到镜子前", "e": "The alarm **goes off** at six thirty, and I hit snooze exactly once.", "z": "闹钟六点半响，我只按一次稍后提醒。"}, {"c": "清晨·从闹钟到镜子前", "e": "I **stretch** my arms above my head until my back cracks.", "z": "我把手臂举过头顶伸个懒腰，后背咔咔响。"}, {"c": "清晨·从闹钟到镜子前", "e": "First things first: I **fold the quilt** into a neat square.", "z": "头等大事：把被子叠成整齐的方块。"}, {"c": "清晨·从闹钟到镜子前", "e": "I pull back the **curtains** and let the morning light pour in.", "z": "我拉开窗帘，让晨光洒进来。"}, {"c": "清晨·从闹钟到镜子前", "e": "The window opens with a squeak — ah, **fresh air** at last.", "z": "窗户吱呀一声打开——啊，终于呼吸到新鲜空气。"}, {"c": "清晨·从闹钟到镜子前", "e": "I shuffle to the bathroom in my **slippers**, still half asleep.", "z": "我趿着拖鞋挪进洗手间，人还半梦半醒。"}, {"c": "清晨·从闹钟到镜子前", "e": "A blob of **toothpaste**, two minutes of brushing, no shortcuts.", "z": "挤一坨牙膏，刷满两分钟，绝不偷工减料。"}, {"c": "清晨·从闹钟到镜子前", "e": "I splash **warm water** on my face and finally wake up properly.", "z": "往脸上泼几捧温水，这才算真正醒了。"}, {"c": "清晨·从闹钟到镜子前", "e": "A quick look in the **mirror** — hair up, game face on.", "z": "照一眼镜子——头发扎起，进入战斗状态。"}, {"c": "清晨·从闹钟到镜子前", "e": "I **get dressed** in under three minutes; practice makes fast.", "z": "我三分钟内穿好衣服，熟能生巧。"}, {"c": "清晨·从闹钟到镜子前", "e": "Phone, keys, and a hair tie — my morning **essentials**.", "z": "手机、钥匙、皮筋——我的晨间三件套。"}, {"c": "清晨·从闹钟到镜子前", "e": "Six fifty. Time to **wake the kids** — wish me luck.", "z": "六点五十，该叫孩子们起床了——祝我好运。"}, {"c": "清晨·叫醒两个小懒虫", "e": "I knock twice and push the door open **gently**.", "z": "我敲两下门，轻轻推开。"}, {"c": "清晨·叫醒两个小懒虫", "e": "Rise and shine, sweethearts — the **sun is up** and so are we.", "z": "起床啦宝贝们——太阳升起来了，我们也要起来了。"}, {"c": "清晨·叫醒两个小懒虫", "e": "My daughter groans and pulls the quilt **over her head**.", "z": "女儿哼哼着把被子拉过头顶。"}, {"c": "清晨·叫醒两个小懒虫", "e": "I open the curtain a crack, and the light does the **dirty work**.", "z": "我把窗帘拉开一条缝，让阳光当这个坏人。"}, {"c": "清晨·叫醒两个小懒虫", "e": "Five more minutes? Nice try — you said that **yesterday**.", "z": "再睡五分钟？想得美——你昨天也是这么说的。"}, {"c": "清晨·叫醒两个小懒虫", "e": "My son sits up with a **cowlick** pointing straight at the ceiling.", "z": "儿子坐起来，一撮呆毛直指天花板。"}, {"c": "清晨·叫醒两个小懒虫", "e": "I lay out their **school uniforms** on the chairs, socks on top.", "z": "我把校服搭在椅背上，袜子放最上面。"}, {"c": "清晨·叫醒两个小懒虫", "e": "Whoever is **washed and dressed** first picks the breakfast song.", "z": "谁先洗漱穿戴好，谁来点早餐背景音乐。"}, {"c": "清晨·叫醒两个小懒虫", "e": "That worked — suddenly everyone is **racing** to the bathroom.", "z": "这招管用——瞬间人人冲刺去洗手间。"}, {"c": "清晨·叫醒两个小懒虫", "e": "Don't forget to **pee first**, then brush; we've learned that lesson.", "z": "记得先上厕所再刷牙，这教训我们吃过。"}, {"c": "清晨·叫醒两个小懒虫", "e": "I check their **schoolbags** by the door one last time.", "z": "我最后检查一遍放在门口的书包。"}, {"c": "清晨·叫醒两个小懒虫", "e": "Two kids, four shoes, zero tears — a **flawless** launch this morning.", "z": "俩孩子、四只鞋、零哭闹——今早完美发射。"}, {"c": "清晨·十五分钟中式早餐", "e": "I set the pot of **millet congee** going before anything else.", "z": "我第一件事是把小米粥坐上锅。"}, {"c": "清晨·十五分钟中式早餐", "e": "While it simmers, I **steam** four baozi from the freezer.", "z": "粥小火熬着，我从冷冻拿四个包子上锅蒸。"}, {"c": "清晨·十五分钟中式早餐", "e": "Two eggs go into boiling water — **seven minutes** for a soft yolk.", "z": "两个鸡蛋下开水——七分钟，溏心正好。"}, {"c": "清晨·十五分钟中式早餐", "e": "I **whisk** two more eggs for the little one who hates shells.", "z": "我再打散两个蛋，给那个嫌剥壳麻烦的小家伙做蛋羹。"}, {"c": "清晨·十五分钟中式早餐", "e": "A drop of **sesame oil** on top, and the kitchen smells like home.", "z": "滴一滴香油，整个厨房都是家的味道。"}, {"c": "清晨·十五分钟中式早餐", "e": "I slice a **cucumber** thin and dress it with a splash of vinegar.", "z": "黄瓜切薄片，淋一点醋凉拌。"}, {"c": "清晨·十五分钟中式早餐", "e": "The congee is bubbling — I give it a **stir** so it won't stick.", "z": "粥咕嘟咕嘟了——搅一搅防止糊底。"}, {"c": "清晨·十五分钟中式早餐", "e": "Bowls out, **chopsticks** down, milk warmed to just-right.", "z": "碗摆好，筷子放好，牛奶温到刚刚好。"}, {"c": "清晨·十五分钟中式早餐", "e": "Breakfast is served — come while it's **hot**, people!", "z": "早餐上桌——各位，趁热来吃！"}, {"c": "清晨·十五分钟中式早餐", "e": "I pack a **spare** baozi for my husband; he always runs late.", "z": "我给老公多装一个包子，他总是赶时间。"}, {"c": "清晨·十五分钟中式早餐", "e": "Someone says the congee is too hot — **blow on it**, my love.", "z": "有人喊粥太烫——那就吹一吹呀宝贝。"}, {"c": "清晨·十五分钟中式早餐", "e": "Fifteen minutes, four dishes, zero takeout — **mum wins** again.", "z": "十五分钟四样早餐零外卖——妈妈又赢一局。"}, {"c": "清晨·出门前的最后检查", "e": "Seven twenty — we enter **countdown mode**.", "z": "七点二十——进入倒计时模式。"}, {"c": "清晨·出门前的最后检查", "e": "Water bottles **filled**? Check. Red scarves on? Check.", "z": "水杯装满了？好。红领巾戴了？好。"}, {"c": "清晨·出门前的最后检查", "e": "Is your **homework** actually inside the bag, not on the desk?", "z": "作业是真的在书包里，不是还躺在书桌上吧？"}, {"c": "清晨·出门前的最后检查", "e": "I feel the radiator of a forehead — no, that's just **sweat** from rushing.", "z": "我摸摸那个滚烫的额头——还好，只是跑出来的汗。"}, {"c": "清晨·出门前的最后检查", "e": "Jackets on; the forecast says it turns **chilly** after four.", "z": "外套穿上，天气预报说四点后转凉。"}, {"c": "清晨·出门前的最后检查", "e": "I switch off the **gas valve** and give it a second look.", "z": "我关掉燃气阀，再确认看一眼。"}, {"c": "清晨·出门前的最后检查", "e": "Lights off, **balcony door** locked, kettle unplugged.", "z": "关灯，锁好阳台门，拔掉烧水壶。"}, {"c": "清晨·出门前的最后检查", "e": "Keys, phone, wallet — the **holy trinity** — all present.", "z": "钥匙、手机、钱包——出门三大件——全都在。"}, {"c": "清晨·出门前的最后检查", "e": "Everybody grab your **own** bag; mum is not a porter.", "z": "各自背好各自的包，妈妈不是搬运工。"}, {"c": "清晨·出门前的最后检查", "e": "Shoes on at the **doorway**, and yes, heels properly in.", "z": "在门口把鞋穿好，对，脚后跟提上去。"}, {"c": "清晨·出门前的最后检查", "e": "I press the **lift button** while herding two small humans.", "z": "我一边按电梯一边赶着两只小人类。"}, {"c": "清晨·出门前的最后检查", "e": "Door locked, double-checked — and we are **out**!", "z": "门锁好，再拉一下确认——出发！"}, {"c": "清晨·送学路上的碎碎念", "e": "Hold my hand at the **crossing**; the light is about to change.", "z": "过马路牵住我的手，灯马上要变了。"}, {"c": "清晨·送学路上的碎碎念", "e": "Green means go, but we still **look both ways** — always.", "z": "绿灯是可以走，但我们照样左右看——永远如此。"}, {"c": "清晨·送学路上的碎碎念", "e": "Mind that **electric bike**; they come out of nowhere.", "z": "当心那辆电动车，它们总是神出鬼没。"}, {"c": "清晨·送学路上的碎碎念", "e": "The osmanthus by the gate smells amazing — take a **deep sniff**.", "z": "校门口的桂花真香——深深闻一口。"}, {"c": "清晨·送学路上的碎碎念", "e": "Quick quiz: how do you say 豆浆 in **English**? Soy milk!", "z": "快问快答：豆浆英语怎么说？Soy milk！"}, {"c": "清晨·送学路上的碎碎念", "e": "Remember to **hand in** the form to Ms Wang first thing.", "z": "记得一到学校先把回执交给王老师。"}, {"c": "清晨·送学路上的碎碎念", "e": "Drink water at **break time**, not just when I remind you.", "z": "课间要喝水，别等我提醒才喝。"}, {"c": "清晨·送学路上的碎碎念", "e": "If anything happens, tell the **teacher** first, then me.", "z": "有任何事，先告诉老师，再告诉我。"}, {"c": "清晨·送学路上的碎碎念", "e": "One hug each — quick, before your **classmates** see us.", "z": "一人抱一下——快点，别让同学看见。"}, {"c": "清晨·送学路上的碎碎念", "e": "Have a great day; I'll be here at **half past four**.", "z": "祝今天顺利，四点半我在这儿等你们。"}, {"c": "清晨·送学路上的碎碎念", "e": "They vanish through the gate without **looking back** — growing up, huh.", "z": "他们头也不回地进了校门——是长大了啊。"}, {"c": "清晨·送学路上的碎碎念", "e": "And just like that, the morning **marathon** is complete.", "z": "就这样，清晨马拉松圆满完赛。"}, {"c": "菜市场·像老手一样买菜", "e": "The **wet market** at eight is a symphony of shouting and scales.", "z": "八点的菜市场，是吆喝声和秤盘声的交响乐。"}, {"c": "菜市场·像老手一样买菜", "e": "I always start at the **vegetable stalls** and loop clockwise.", "z": "我习惯从蔬菜摊开始，顺时针逛一圈。"}, {"c": "菜市场·像老手一样买菜", "e": "Boss, is the water spinach **picked this morning**?", "z": "老板，这空心菜是今早现摘的吗？"}, {"c": "菜市场·像老手一样买菜", "e": "I press the tomato lightly — **firm**, heavy, no soft spots.", "z": "我轻轻捏一下番茄——硬实、压手、没有软点。"}, {"c": "菜市场·像老手一样买菜", "e": "Two jin of these, and please pick the **straight** cucumbers.", "z": "来两斤，麻烦挑直溜的黄瓜。"}, {"c": "菜市场·像老手一样买菜", "e": "Can you do **eight yuan**? I'm here every other day.", "z": "八块行不行？我隔天就来一趟。"}, {"c": "菜市场·像老手一样买菜", "e": "Deal — and he **throws in** a handful of cilantro. A pro move.", "z": "成交——他还送了一把香菜，老江湖了。"}, {"c": "菜市场·像老手一样买菜", "e": "At the fish stall, I ask for it **scaled and gutted**.", "z": "到鱼摊，我让老板刮鳞去内脏。"}, {"c": "菜市场·像老手一样买菜", "e": "Make the ribs **chunky**; they're going into soup.", "z": "排骨剁大块，回去炖汤。"}, {"c": "菜市场·像老手一样买菜", "e": "I **scan the QR code** and the vendor's speaker sings the amount.", "z": "我扫码付款，摊主的音箱唱出金额。"}, {"c": "菜市场·像老手一样买菜", "e": "My tote bags are **bursting** — cheaper and greener than plastic.", "z": "两个布袋子塞得鼓鼓的——比塑料袋省钱又环保。"}, {"c": "菜市场·像老手一样买菜", "e": "Total damage: forty-six yuan for **three days** of dinners.", "z": "总共花了四十六元，够三天的晚饭。"}, {"c": "厨房·买菜回家的整理术", "e": "Bags on the counter — now comes the **sorting** ritual.", "z": "袋子上台面——现在开始收纳仪式。"}, {"c": "厨房·买菜回家的整理术", "e": "Leafy greens get a paper towel and go in the **crisper drawer**.", "z": "叶菜垫张厨房纸，放进冰箱保鲜抽屉。"}, {"c": "厨房·买菜回家的整理术", "e": "Do NOT wash the greens **before** storing; they rot faster wet.", "z": "叶菜存放前千万别洗，带水烂得快。"}, {"c": "厨房·买菜回家的整理术", "e": "The tomatoes stay **on the counter**; the fridge kills their flavour.", "z": "番茄放台面就行，进冰箱会失去风味。"}, {"c": "厨房·买菜回家的整理术", "e": "Ginger and garlic live in the **ventilated basket** by the window.", "z": "姜和蒜住在窗边的透气篮里。"}, {"c": "厨房·买菜回家的整理术", "e": "I **portion** the ribs into two bags — one for today, one frozen.", "z": "排骨分成两袋——一袋今天用，一袋冷冻。"}, {"c": "厨房·买菜回家的整理术", "e": "Label the bag with today's **date**; future me will thank present me.", "z": "袋子上写好今天的日期，未来的我会感谢现在的我。"}, {"c": "厨房·买菜回家的整理术", "e": "The fish gets a quick **rinse** and a bed of ice in the fridge.", "z": "鱼冲洗一下，垫冰放进冷藏。"}, {"c": "厨房·买菜回家的整理术", "e": "Mushrooms hate plastic — a **paper bag** keeps them dry.", "z": "蘑菇讨厌塑料袋——纸袋才能保持干燥。"}, {"c": "厨房·买菜回家的整理术", "e": "I stand the green onions in a jar of water like a **bouquet**.", "z": "小葱插进水杯里，像一束花。"}, {"c": "厨房·买菜回家的整理术", "e": "Old leftovers move to the **front shelf**: eat me first.", "z": "旧剩菜挪到冰箱最前排：先吃我。"}, {"c": "厨房·买菜回家的整理术", "e": "Ten minutes of sorting saves a week of **waste** — worth it.", "z": "十分钟收纳，省下一周的浪费——值。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "Tonight's green: a fat bundle of **Shanghai greens**.", "z": "今晚的青菜：一大把上海青。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "I trim the roots and **separate** the leaves one by one.", "z": "我切掉根部，把叶子一片片掰开。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "Into a basin of water — swish, swish — to **shake off** the sand.", "z": "放进水盆——哗啦哗啦——把泥沙涮掉。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "Meanwhile, I **smash** four garlic cloves with the flat of my knife.", "z": "同时，我用刀面拍碎四瓣蒜。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "The wok goes on **high heat** until a drop of water dances.", "z": "炒锅开大火，烧到滴水成珠跳舞。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "Two spoons of oil, swirl to **coat** the sides.", "z": "两勺油，转锅让油挂满锅壁。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "Garlic in — listen to that **sizzle** — ten seconds, no more.", "z": "下蒜——听这滋啦声——十秒，绝不多。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "Greens in, and I **toss** fast so nothing burns.", "z": "青菜下锅，快速翻炒，一点不能糊。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "A pinch of salt, a splash of water, lid on for **thirty seconds**.", "z": "一撮盐，一点水，盖上锅盖焖三十秒。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "Look at that colour — **emerald green**, still crisp.", "z": "看这颜色——翠绿翠绿，还是脆的。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "Off the heat, onto the plate, done in **four minutes** flat.", "z": "关火装盘，整整四分钟搞定。"}, {"c": "厨房·一道蒜蓉青菜的全程口播", "e": "Rule of thumb: with greens, the wok waits for **no one**.", "z": "经验之谈：炒青菜，锅是不等人的。"}, {"c": "厨房·红烧排骨完整流程", "e": "The ribs get a **cold-water** bath first — bring it slowly to a boil.", "z": "排骨先冷水下锅——慢慢烧开。"}, {"c": "厨房·红烧排骨完整流程", "e": "Skim off the grey **foam**; that's where the odd smell lives.", "z": "撇掉灰色浮沫，腥味就藏在那里面。"}, {"c": "厨房·红烧排骨完整流程", "e": "Drain, rinse, and pat the ribs **dry** — wet meat won't brown.", "z": "捞出冲净，把排骨擦干——带水的肉上不了色。"}, {"c": "厨房·红烧排骨完整流程", "e": "A little oil, a spoon of sugar, and I stir until it turns **amber**.", "z": "少许油，一勺糖，炒到琥珀色。"}, {"c": "厨房·红烧排骨完整流程", "e": "Ribs in — **coat** every piece in that caramel shine.", "z": "排骨下锅——让每一块都裹上糖色。"}, {"c": "厨房·红烧排骨完整流程", "e": "Ginger slices, two star anise, a **splash** of cooking wine.", "z": "姜片、两颗八角、烹一点料酒。"}, {"c": "厨房·红烧排骨完整流程", "e": "Soy sauce for flavour, dark soy for **colour** — know the difference.", "z": "生抽提味，老抽上色——这俩得分清。"}, {"c": "厨房·红烧排骨完整流程", "e": "Hot water to **cover**, never cold — cold water toughens the meat.", "z": "加热水没过排骨，千万别加冷水——冷水肉会柴。"}, {"c": "厨房·红烧排骨完整流程", "e": "Lid on, small flame, and now we **wait** forty minutes.", "z": "盖上盖子，转小火，接下来交给四十分钟。"}, {"c": "厨房·红烧排骨完整流程", "e": "The whole flat smells like a **holiday** already.", "z": "整个屋子已经闻起来像过节了。"}, {"c": "厨房·红烧排骨完整流程", "e": "Final act: high heat to **reduce** the sauce until it clings.", "z": "最后一步：开大火收汁，收到挂勺。"}, {"c": "厨房·红烧排骨完整流程", "e": "Sprinkle of spring onion, and dinner's **centrepiece** is ready.", "z": "撒把葱花，今晚的硬菜完成。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "Rice first: two cups, rinsed until the water runs **almost clear**.", "z": "先煮饭：两杯米，淘到水基本变清。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "Water level: first knuckle of my **index finger** — grandma's rule.", "z": "水量：食指第一节——奶奶传下来的标准。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "Rice cooker on; that little song means the timer is **set**.", "z": "按下电饭煲，那声音一响就是定好了。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "Soup pot next: winter melon and dried shrimp, a **light** combo.", "z": "接着汤锅：冬瓜配虾皮，清淡组合。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "I cut the melon into **mahjong-sized** cubes — tradition.", "z": "冬瓜切成麻将块——老规矩。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "While it simmers, I wipe the table and lay out **four sets** of bowls.", "z": "汤煨着，我擦好桌子，摆四套碗筷。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "Chopsticks on the **right**, soup spoons resting in the bowls.", "z": "筷子放右手边，汤勺搁在碗里。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "Kids, wash your hands — dinner lands in **five minutes**!", "z": "孩子们去洗手——晚饭五分钟后降落！"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "A final **taste** of the soup... needs three more grains of salt.", "z": "最后尝一口汤……还差三粒盐。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "White pepper at the end, so the aroma doesn't **cook off**.", "z": "白胡椒最后放，香气才不会煮跑。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "Serve the elders **first** — that's how we do it at this table.", "z": "先给长辈盛——我们这张桌的规矩。"}, {"c": "厨房·汤、饭、摆桌三线作战", "e": "Three dishes, one soup, steaming rice — **battle** won.", "z": "三菜一汤，米饭喷香——战斗胜利。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "Everyone carries their **own bowl** to the sink — house law.", "z": "每个人把自己的碗端到水槽——家规。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "Leftovers go into **glass boxes** while they're still warm.", "z": "剩菜趁温装进玻璃保鲜盒。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "Tonight's soup becomes tomorrow's **noodle base** — zero waste.", "z": "今晚的汤就是明天的面汤底——零浪费。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "I scrape the plates first; grease down the drain means a **clog** later.", "z": "盘子先刮干净，油倒进下水道迟早堵。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "Hot water, a drop of soap, and the bowls **squeak** clean.", "z": "热水加一滴洗洁精，碗洗得吱吱响。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "The wok gets washed **while warm** — five times easier.", "z": "炒锅趁热洗——省五倍力气。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "Dry it on the fire for ten seconds so it never **rusts**.", "z": "上火烘十秒，锅永远不生锈。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "I wipe the stove and the **backsplash** before the oil sets.", "z": "趁油渍没干，擦掉灶台和挡油板。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "Range hood filter — I give it a look; next weekend, a **deep clean**.", "z": "瞄一眼油烟机滤网——下周末安排大扫除。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "Cloth rinsed, wrung, and hung to **air dry** — not balled up wet.", "z": "抹布冲净拧干挂起来晾——不能湿着团成一坨。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "Counter clear, sink empty, lights off — kitchen **closed**.", "z": "台面清空，水槽见底，关灯——厨房打烊。"}, {"c": "厨房·饭后收尾的正确姿势", "e": "A closed kitchen at night equals a **happy** kitchen at dawn.", "z": "晚上收干净的厨房，等于清晨心情好的厨房。"}, {"c": "家务·洗衣晾衣一条龙", "e": "Laundry day: I **sort** by colour first — whites, darks, and school uniforms.", "z": "洗衣日：先按颜色分——白的、深的、校服单独一堆。"}, {"c": "家务·洗衣晾衣一条龙", "e": "Pockets get checked; last week I laundered a **tissue** into a snowstorm.", "z": "口袋都要掏，上周我把纸巾洗成了漫天雪花。"}, {"c": "家务·洗衣晾衣一条龙", "e": "Socks go into the **mesh bag** so they stop eating each other.", "z": "袜子装进洗衣袋，省得它们互相吞掉。"}, {"c": "家务·洗衣晾衣一条龙", "e": "Collar stains get a dab of **laundry soap** and a little scrub.", "z": "领口污渍抹点洗衣皂，搓两下。"}, {"c": "家务·洗衣晾衣一条龙", "e": "Detergent in the drawer, softener in its **slot** — not together.", "z": "洗衣液进料盒，柔顺剂进它自己的格——别倒一起。"}, {"c": "家务·洗衣晾衣一条龙", "e": "I pick the **quick wash** cycle; these clothes aren't that dirty.", "z": "我选快洗档，这些衣服没那么脏。"}, {"c": "家务·洗衣晾衣一条龙", "e": "Forty minutes later, the machine sings its **victory** tune.", "z": "四十分钟后，洗衣机唱起胜利之歌。"}, {"c": "家务·洗衣晾衣一条龙", "e": "Shake each piece twice before hanging — fewer **wrinkles**, less ironing.", "z": "每件抖两下再晾——褶子少，熨烫也少。"}, {"c": "家务·洗衣晾衣一条龙", "e": "Shirts on hangers, trousers by the **cuffs**, socks in pairs.", "z": "衬衫上衣架，裤子夹裤脚，袜子成双夹。"}, {"c": "家务·洗衣晾衣一条龙", "e": "Sun-facing side for towels; they dry **crispy** and smell like sunshine.", "z": "毛巾晾向阳面，干得脆脆的，一股太阳味。"}, {"c": "家务·洗衣晾衣一条龙", "e": "Undies dry on the **inner rack**, away from curious neighbours.", "z": "内衣晾里侧，避开好奇的邻居视线。"}, {"c": "家务·洗衣晾衣一条龙", "e": "The balcony looks like a flag ceremony — mission **accomplished**.", "z": "阳台像升旗仪式现场——任务完成。"}, {"c": "家务·客厅三十分钟闪电战", "e": "Timer set: **thirty minutes** to make this living room presentable.", "z": "定时开始：三十分钟让客厅见得了人。"}, {"c": "家务·客厅三十分钟闪电战", "e": "Step one: everything on the floor goes back to its **home**.", "z": "第一步：地上所有东西各回各家。"}, {"c": "家务·客厅三十分钟闪电战", "e": "Toys in the toy box; whoever left this **Lego** here owes me a foot.", "z": "玩具进玩具箱；乐高的主人欠我一只脚的赔偿。"}, {"c": "家务·客厅三十分钟闪电战", "e": "Cushions **plumped** and lined up at the same angle — satisfying.", "z": "抱枕拍蓬，按同一个角度排好——强迫症舒适了。"}, {"c": "家务·客厅三十分钟闪电战", "e": "I dust from **top to bottom**: shelves first, floor last.", "z": "擦灰从上往下：先架子，最后地板。"}, {"c": "家务·客厅三十分钟闪电战", "e": "The TV screen gets a dry cloth only — no **spray** directly on it.", "z": "电视屏幕只能干擦——清洁剂不能直接喷。"}, {"c": "家务·客厅三十分钟闪电战", "e": "Remote controls: found two, still **missing** one. Classic.", "z": "遥控器找到两个，还失踪一个，经典剧情。"}, {"c": "家务·客厅三十分钟闪电战", "e": "Under the sofa lives a **civilization**: three socks, one crayon, five crumbs.", "z": "沙发底下藏着一个文明：三只袜子、一支蜡笔、五粒饼干渣。"}, {"c": "家务·客厅三十分钟闪电战", "e": "Vacuum first, then a **damp mop** in the corners.", "z": "先吸尘，边角再用湿拖把过一遍。"}, {"c": "家务·客厅三十分钟闪电战", "e": "I water the **potted plants** and turn them toward the light.", "z": "给绿植浇浇水，把它们转向阳光。"}, {"c": "家务·客厅三十分钟闪电战", "e": "A quick spray of air freshener — the **finishing touch**.", "z": "喷一下空气清新剂——点睛之笔。"}, {"c": "家务·客厅三十分钟闪电战", "e": "Timer beeps at twenty-eight minutes — a new **personal best**!", "z": "计时器在二十八分钟响起——个人新纪录！"}, {"c": "家务·换床单的仪式感", "e": "It's Sunday, which in this house means **fresh sheets** day.", "z": "周日，在我们家等于换床单日。"}, {"c": "家务·换床单的仪式感", "e": "I strip the bed and toss everything into one big **pile**.", "z": "我把床全部扒光，堆成一座小山。"}, {"c": "家务·换床单的仪式感", "e": "The mattress gets a **vacuum** — you'd be amazed what lives there.", "z": "床垫吸一遍尘——里面住着什么你想都想不到。"}, {"c": "家务·换床单的仪式感", "e": "Then I **flip** it; rotating the mattress makes it last years longer.", "z": "然后给床垫翻个面，轮换着用能多睡好几年。"}, {"c": "家务·换床单的仪式感", "e": "Fitted sheet first: fight the **corners** clockwise, always win.", "z": "先套床笠：顺时针一个角一个角来，必胜。"}, {"c": "家务·换床单的仪式感", "e": "The duvet cover trick: **roll** it like a burrito, then flip.", "z": "被套小妙招：像卷煎饼一样卷起来再翻。"}, {"c": "家务·换床单的仪式感", "e": "Pillows get a good **fluff** and two hours of sunshine.", "z": "枕头拍打蓬松，再晒两小时太阳。"}, {"c": "家务·换床单的仪式感", "e": "Buckwheat pillows can't be washed — just **sun** them, grandma says.", "z": "荞麦枕不能洗——晒就行，奶奶说的。"}, {"c": "家务·换床单的仪式感", "e": "I tuck the corners **hospital-style**, tight enough to bounce a coin.", "z": "床角掖成医院式，紧到能弹硬币。"}, {"c": "家务·换床单的仪式感", "e": "Fresh pillowcases snap in the air like little **flags**.", "z": "新枕套在空中一抖，啪啪响像小旗子。"}, {"c": "家务·换床单的仪式感", "e": "The whole room instantly smells like **clean cotton**.", "z": "整个房间瞬间是干净棉布的味道。"}, {"c": "家务·换床单的仪式感", "e": "Tonight's sleep is already **guaranteed** five-star.", "z": "今晚的睡眠已提前锁定五星级。"}, {"c": "家务·洗手间深度清洁", "e": "Gloves on — the bathroom **deep clean** begins.", "z": "手套戴好——洗手间大扫除开始。"}, {"c": "家务·洗手间深度清洁", "e": "Cleaner goes on the tiles first and needs ten minutes to **soak**.", "z": "清洁剂先喷瓷砖，需要泡上十分钟。"}, {"c": "家务·洗手间深度清洁", "e": "Meanwhile, I **descale** the shower head in a bag of vinegar.", "z": "趁这时间，我用醋袋子给花洒除水垢。"}, {"c": "家务·洗手间深度清洁", "e": "The mirror gets glass cleaner and a **newspaper** shine — old trick.", "z": "镜子喷玻璃水，用旧报纸擦亮——老办法。"}, {"c": "家务·洗手间深度清洁", "e": "Toothbrush cups grow a pink ring if you **ignore** them — scrub!", "z": "漱口杯不管它就会长粉圈——刷掉！"}, {"c": "家务·洗手间深度清洁", "e": "The tap fittings polish up with an old **toothbrush**.", "z": "水龙头缝隙用旧牙刷来抛光。"}, {"c": "家务·洗手间深度清洁", "e": "Toilet: cleaner under the **rim**, brush, flush, done.", "z": "马桶：清洁剂打进内圈边，刷，冲，完成。"}, {"c": "家务·洗手间深度清洁", "e": "The floor drain gets a **hair-catcher** check — gross but necessary.", "z": "地漏检查一下毛发过滤网——恶心但必要。"}, {"c": "家务·洗手间深度清洁", "e": "I run the **exhaust fan** so the mould never gets ideas.", "z": "排气扇打开，让霉菌死了这条心。"}, {"c": "家务·洗手间深度清洁", "e": "Towels swapped for fresh ones, old ones **demoted** to rag duty.", "z": "毛巾换新，旧的降级当抹布。"}, {"c": "家务·洗手间深度清洁", "e": "Floor mopped **backwards** toward the door — never paint yourself in.", "z": "地从里往外倒退着拖——别把自己困在角落。"}, {"c": "家务·洗手间深度清洁", "e": "Squeaky, shiny, lemon-scented — inspection **passed**.", "z": "吱吱响、亮堂堂、柠檬香——验收通过。"}, {"c": "家务·垃圾分类出门记", "e": "The bin is announcing itself — time for the **rubbish run**.", "z": "垃圾桶已经开始自我介绍了——该去倒垃圾了。"}, {"c": "家务·垃圾分类出门记", "e": "Kitchen waste in the **green** bucket: peels, bones, leftovers.", "z": "厨余进绿桶：果皮、骨头、剩菜。"}, {"c": "家务·垃圾分类出门记", "e": "Wait — soup counts as kitchen waste, but **drain it** first.", "z": "等等——汤算厨余，但要先滤掉汤水。"}, {"c": "家务·垃圾分类出门记", "e": "Cardboard boxes get **flattened**; the recycling man pays by weight.", "z": "纸箱压扁；收废品师傅按斤称。"}, {"c": "家务·垃圾分类出门记", "e": "Batteries and old medicine are **hazardous** — the red bin, always.", "z": "电池和过期药是有害垃圾——永远进红桶。"}, {"c": "家务·垃圾分类出门记", "e": "Takeout boxes: rinse, then **dry waste** — food gunk ruins recycling.", "z": "外卖盒：冲一下算干垃圾——带着油污就没法回收了。"}, {"c": "家务·垃圾分类出门记", "e": "I tie each bag with a **double knot**; leaky bags are a crime.", "z": "每袋打双结；漏汤的垃圾袋是犯罪。"}, {"c": "家务·垃圾分类出门记", "e": "The kids fight over who **presses the lift button** — take turns!", "z": "俩孩子抢着按电梯——轮流来！"}, {"c": "家务·垃圾分类出门记", "e": "Down at the station, the aunty **supervisor** nods at my sorting.", "z": "楼下垃圾站，监督阿姨对我的分类点头认可。"}, {"c": "家务·垃圾分类出门记", "e": "Green to green, grey to grey — we **feed** each bin its diet.", "z": "绿的进绿桶，灰的进灰桶——各喂各的饭。"}, {"c": "家务·垃圾分类出门记", "e": "Hands washed the second we're back — **non-negotiable**.", "z": "一进家门立刻洗手——没有商量余地。"}, {"c": "家务·垃圾分类出门记", "e": "A light bin and a clear conscience — small chore, real **satisfaction**.", "z": "垃圾清空，心里敞亮——小事一桩，成就感真实。"}, {"c": "厨房·包一顿周末饺子", "e": "Weekend project: **dumplings** from scratch, whole family on deck.", "z": "周末大工程：从零包饺子，全家上阵。"}, {"c": "厨房·包一顿周末饺子", "e": "Grandma commands the **dough**: flour, water, and thirty years of feel.", "z": "奶奶掌管面团：面粉、水，和三十年的手感。"}, {"c": "厨房·包一顿周末饺子", "e": "The filling: minced pork, chopped **chives**, one egg for bounce.", "z": "馅料：猪肉末、切碎的韭菜，加一个鸡蛋更弹。"}, {"c": "厨房·包一顿周末饺子", "e": "Season it, then stir in **one direction** only — that's the secret.", "z": "调好味，只朝一个方向搅——这是诀窍。"}, {"c": "厨房·包一顿周末饺子", "e": "Dad rolls the wrappers: thin at the **edge**, thick in the middle.", "z": "爸爸擀皮：边薄中间厚。"}, {"c": "厨房·包一顿周末饺子", "e": "My job is quality control and **filling** distribution.", "z": "我负责质检和分配馅料。"}, {"c": "厨房·包一顿周末饺子", "e": "Kids' dumplings look like tiny **monsters** — we cook them anyway.", "z": "孩子们包的饺子长得像小怪兽——照煮不误。"}, {"c": "厨房·包一顿周末饺子", "e": "One lucky dumpling hides a **peanut**; finder does no chores today.", "z": "有一颗幸运饺子藏了粒花生米，吃到的今天免做家务。"}, {"c": "厨房·包一顿周末饺子", "e": "Water boils, dumplings dive in, and I add **cold water** three times.", "z": "水开下饺子，我点三次凉水。"}, {"c": "厨房·包一顿周末饺子", "e": "They're done when they **float** like little white boats.", "z": "等它们像小白船一样浮起来就熟了。"}, {"c": "厨房·包一顿周末饺子", "e": "Dipping sauce: vinegar, a thread of **chilli oil**, minced garlic.", "z": "蘸料：醋、一缕辣椒油、蒜末。"}, {"c": "厨房·包一顿周末饺子", "e": "Sixty-eight dumplings, four generations of technique, one loud **happy** table.", "z": "六十八个饺子，四代人的手艺，一桌热闹的幸福。"}, {"c": "清晨·周末的慢启动", "e": "No alarm today — I wake up to **birdsong** and it feels illegal.", "z": "今天不设闹钟——被鸟叫醒，爽得像犯规。"}, {"c": "清晨·周末的慢启动", "e": "I make a pot of **green tea** and claim the sunny end of the sofa.", "z": "泡一壶绿茶，占领沙发向阳的那一头。"}, {"c": "清晨·周末的慢启动", "e": "The kids sleep in; the flat is so quiet I can hear the **fridge hum**.", "z": "孩子们睡懒觉，家里静得能听见冰箱嗡嗡声。"}, {"c": "清晨·周末的慢启动", "e": "I water the balcony plants and **deadhead** two tired flowers.", "z": "我给阳台的花浇水，掐掉两朵谢了的。"}, {"c": "清晨·周末的慢启动", "e": "The pothos grew a new **leaf** overnight — a small miracle.", "z": "绿萝一夜之间冒了片新叶——小小的奇迹。"}, {"c": "清晨·周末的慢启动", "e": "I flip through my planner and **circle** just three tasks for today.", "z": "翻开手账，今天只圈三件事。"}, {"c": "清晨·周末的慢启动", "e": "Rule of weekends: do **less**, but enjoy it more.", "z": "周末守则：做得少一点，但享受多一点。"}, {"c": "清晨·周末的慢启动", "e": "The little one pads out in pajamas, hair like a **bird's nest**.", "z": "小的穿着睡衣踱出来，头发像个鸟窝。"}, {"c": "清晨·周末的慢启动", "e": "We make pancakes together and only burn the **first** one — progress.", "z": "我们一起摊饼，只糊了第一张——进步了。"}, {"c": "清晨·周末的慢启动", "e": "Late breakfast bleeds into early lunch — we call it **brunch** now.", "z": "早饭吃着吃着成了午饭——我们现在管这叫早午餐。"}, {"c": "清晨·周末的慢启动", "e": "Sunlight moves across the floor like a slow **cat**.", "z": "阳光像一只慢吞吞的猫，在地板上挪动。"}, {"c": "清晨·周末的慢启动", "e": "Some mornings are for racing; this one is for **breathing**.", "z": "有的早晨用来奔跑，这个早晨用来呼吸。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "Four o'clock: the after-school **fruit plate** ritual begins.", "z": "四点整：放学水果拼盘仪式开始。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "Apples get sliced last so they don't **brown** — or a dip in salt water.", "z": "苹果最后切才不发黑——或者泡下淡盐水。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "I carve the watermelon into **triangles**, easy for small hands.", "z": "西瓜切成三角块，小手好拿。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "Grapes are washed with a spoonful of **starch** — it lifts the dust off.", "z": "葡萄用一勺淀粉水洗——浮尘全带走。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "Kiwi trick: slice off both ends and **scoop** with a spoon.", "z": "猕猴桃妙招：切掉两头，用勺子一转挖出来。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "The orange becomes a **flower** with six petal cuts — mum magic.", "z": "橙子切六刀变成一朵花——妈妈的魔法。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "A few toothpicks with **cartoon flags** — presentation matters.", "z": "插几根卡通小旗牙签——摆盘很重要。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "No mango today; the little one's **eczema** is acting up.", "z": "今天不放芒果，小的湿疹又有点冒头。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "I sneak in two slices of **dragon fruit** for the fibre.", "z": "我偷偷塞两片火龙果，补充膳食纤维。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "The plate goes on the table right at **eye level** — strategy.", "z": "果盘正好摆在他们视线的高度——这是战术。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "Fruit first, snacks **never** — the house rule stands.", "z": "先吃水果，零食免谈——家规不动摇。"}, {"c": "厨房·给孩子准备水果拼盘", "e": "Two kids, one plate, zero survivors — **cleanest** plate in China.", "z": "俩孩子一盘水果零幸存——全中国最干净的盘子。"}, {"c": "家务·晒被子的大日子", "e": "Blue sky, dry wind — a **quilt-sunning** day if I ever saw one.", "z": "蓝天配干风——这不晒被子简直天理难容。"}, {"c": "家务·晒被子的大日子", "e": "I check the **forecast** twice; a surprise shower would be tragedy.", "z": "天气预报确认两遍，突然下雨就是悲剧。"}, {"c": "家务·晒被子的大日子", "e": "The quilts go over the balcony rail with a **firm shake** first.", "z": "被子先用力抖一抖，再搭上阳台栏杆。"}, {"c": "家务·晒被子的大日子", "e": "Clip them down — the wind here has **stolen** a pillowcase before.", "z": "夹子夹牢——这里的风偷过一个枕套。"}, {"c": "家务·晒被子的大日子", "e": "Two hours per side, then a **flip**, like grilling something cosy.", "z": "一面晒两小时再翻面，像在烤一床温柔。"}, {"c": "家务·晒被子的大日子", "e": "The dust gets a gentle **pat**, not a beating — fibres are delicate.", "z": "灰尘轻轻拍，不能猛打——纤维很娇气。"}, {"c": "家务·晒被子的大日子", "e": "Meanwhile the pillows line up on the **windowsill** like fat cats.", "z": "枕头们在窗台排排坐，像几只胖猫。"}, {"c": "家务·晒被子的大日子", "e": "I rotate the **mattress topper** into the patch of sun too.", "z": "床褥也转到有太阳的位置轮着晒。"}, {"c": "家务·晒被子的大日子", "e": "Neighbour aunty nods at my setup: the highest form of **approval**.", "z": "邻居阿姨对我的晾晒阵型点头：这是最高认证。"}, {"c": "家务·晒被子的大日子", "e": "By four, everything comes in **toasty** and twice as fluffy.", "z": "四点前收进来，暖烘烘的，蓬松了一倍。"}, {"c": "家务·晒被子的大日子", "e": "That baked-sunshine smell has a name in this family: **happiness**.", "z": "那股太阳烤过的味道，在我们家有个名字：幸福。"}, {"c": "家务·晒被子的大日子", "e": "Tonight, everyone will sleep like **dumplings** in a steamer.", "z": "今晚，全家都会睡得像蒸笼里的饺子。"}, {"c": "亲子·校门口的重逢", "e": "Four twenty-five: I claim my **spot** by the school gate.", "z": "四点二十五：我在校门口占好我的老位置。"}, {"c": "亲子·校门口的重逢", "e": "The bell rings and the gate **erupts** with small humans.", "z": "铃声一响，校门喷涌出一群小人类。"}, {"c": "亲子·校门口的重逢", "e": "There they are — one waving, one dragging a **jacket** on the ground.", "z": "来了——一个在挥手，一个拖着外套擦地。"}, {"c": "亲子·校门口的重逢", "e": "First question, always: are you **hungry** or just tired?", "z": "第一个问题永远是：你是饿了还是累了？"}, {"c": "亲子·校门口的重逢", "e": "I take the water bottle, not the **schoolbag** — their bag, their job.", "z": "我接过水杯，不接书包——自己的书包自己背。"}, {"c": "亲子·校门口的重逢", "e": "Tell me the **best** thing and the worst thing about today.", "z": "跟我说说今天最棒的一件事和最糟的一件事。"}, {"c": "亲子·校门口的重逢", "e": "He scored a goal at PE; she traded **stickers** with her deskmate.", "z": "他体育课进了个球；她和同桌换了贴纸。"}, {"c": "亲子·校门口的重逢", "e": "The worst thing? The maths quiz had a **tricky** last question.", "z": "最糟的事？数学小测最后一题很刁钻。"}, {"c": "亲子·校门口的重逢", "e": "We'll look at it together after the fruit — no **stress** now.", "z": "吃完水果我们一起看——现在不焦虑。"}, {"c": "亲子·校门口的重逢", "e": "We stop to smell the **osmanthus**; some things can't wait.", "z": "我们停下来闻桂花，有些事等不得。"}, {"c": "亲子·校门口的重逢", "e": "Race you to the **community gate** — loser sets the table!", "z": "比赛跑到小区大门——输的摆碗筷！"}, {"c": "亲子·校门口的重逢", "e": "I lose by three steps, exactly as **planned**.", "z": "我恰好输三步，一切尽在计划之中。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "Snack done, hands washed — the **homework hour** begins.", "z": "加餐完毕，手也洗了——作业时间开始。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "First, we **empty** the schoolbag and line up today's tasks.", "z": "首先清空书包，把今天的任务排成一排。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "Three assignments: maths sheet, **copying** words, and reading aloud.", "z": "三项作业：数学卷、抄写生词、朗读。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "Which one is the **hardest**? We start with that one.", "z": "哪个最难？我们就从那个开始。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "Desk cleared, water within reach, phone **out of sight** — mine too.", "z": "桌面清空，水放手边，手机拿走——我的也一样。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "The timer is set for **twenty-five minutes**, then a stretch break.", "z": "计时二十五分钟，然后起来活动一下。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "I sit nearby with my own book — company, not **surveillance**.", "z": "我拿本自己的书坐旁边——是陪伴，不是监工。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "Stuck? Read the question **out loud** twice before you call me.", "z": "卡住了？先把题目大声读两遍，再叫我。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "She underlines the **key numbers** — good habit, quietly praised.", "z": "她把关键数字划了出来——好习惯，默默点赞。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "His character strokes are wandering — **slow down**, buddy.", "z": "他的笔画开始飘了——慢一点，伙计。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "Timer beeps; everyone up for **jumping jacks**, me included.", "z": "计时器响了，全体起立做开合跳，包括我。"}, {"c": "亲子·作业陪伴的开场十分钟", "e": "Round one done; two more to go — steady **wins** the evening.", "z": "第一轮结束，还剩两项——稳住，就能赢下今晚。"}, {"c": "亲子·检查作业不翻车指南", "e": "He says he's **finished** — famous last words; let's verify.", "z": "他说写完了——经典遗言，来验证一下。"}, {"c": "亲子·检查作业不翻车指南", "e": "I check the list first: is every item actually **ticked off**?", "z": "我先对清单：每一项真的都勾掉了吗？"}, {"c": "亲子·检查作业不翻车指南", "e": "Aha — the reading homework was hiding on the **back** of the sheet.", "z": "啊哈——朗读作业藏在卷子背面。"}, {"c": "亲子·检查作业不翻车指南", "e": "For maths, I only mark **which** ones are wrong, never the answer.", "z": "数学我只标哪题错了，绝不直接给答案。"}, {"c": "亲子·检查作业不翻车指南", "e": "Two mistakes: one careless, one a real **knowledge gap**.", "z": "错了两道：一道是粗心，一道是真不会。"}, {"c": "亲子·检查作业不翻车指南", "e": "The careless one he **spots** in five seconds — see? You knew it.", "z": "粗心那道他五秒就发现了——瞧，你其实会。"}, {"c": "亲子·检查作业不翻车指南", "e": "The hard one we solve with **drawing** — a picture beats a lecture.", "z": "难的那道我们画图解决——一张图胜过十句大道理。"}, {"c": "亲子·检查作业不翻车指南", "e": "Wrong answers go into the **mistake notebook**, tonight's harvest.", "z": "错题抄进错题本，这是今晚的收获。"}, {"c": "亲子·检查作业不翻车指南", "e": "Tomorrow morning he'll **re-do** just these two, fresh brain, two minutes.", "z": "明早只重做这两题，脑子清醒，两分钟的事。"}, {"c": "亲子·检查作业不翻车指南", "e": "I sign the form and write one **specific** praise for the teacher to see.", "z": "我签好字，写一句具体的表扬让老师看到。"}, {"c": "亲子·检查作业不翻车指南", "e": "Bag packed tonight, by **his own** hands, checked once by mine.", "z": "书包今晚装好，他自己动手，我复查一遍。"}, {"c": "亲子·检查作业不翻车指南", "e": "We end on a high five — homework is a **team sport** here.", "z": "我们击掌收工——在这个家，作业是团队运动。"}, {"c": "亲子·姐弟大战调解现场", "e": "A crash, a shout — the living room has become a **courtroom**.", "z": "一声巨响一声喊——客厅变成了法庭。"}, {"c": "亲子·姐弟大战调解现场", "e": "Both of you, **freeze**. Hands off, voices down.", "z": "你们俩，静止。手放开，音量降下来。"}, {"c": "亲子·姐弟大战调解现场", "e": "I'm not asking who **started** it; I'm asking what happened.", "z": "我不问是谁先动的手，我问发生了什么。"}, {"c": "亲子·姐弟大战调解现场", "e": "One at a time — she speaks, you **listen**, then we switch.", "z": "一个一个说——她讲的时候你听，然后交换。"}, {"c": "亲子·姐弟大战调解现场", "e": "So the fight is over the **last** piece of the puzzle. A classic.", "z": "所以是为了拼图的最后一块。经典案件。"}, {"c": "亲子·姐弟大战调解现场", "e": "Feelings are allowed; **grabbing** is not.", "z": "有情绪可以，抢东西不行。"}, {"c": "亲子·姐弟大战调解现场", "e": "What could you do **instead** next time? Think of two ways.", "z": "下次可以怎么做？想出两个办法来。"}, {"c": "亲子·姐弟大战调解现场", "e": "Rock-paper-scissors for the last piece — accepted by **both parties**.", "z": "最后一块石头剪刀布决定——双方均表示接受。"}, {"c": "亲子·姐弟大战调解现场", "e": "Now the apologies — eyes on each other, and **mean it**.", "z": "现在道歉——看着对方的眼睛，要走心。"}, {"c": "亲子·姐弟大战调解现场", "e": "Hug it out; you don't have to like it, just **do it**... see, you're smiling.", "z": "抱一个；不情愿也得抱……看，你们都笑了。"}, {"c": "亲子·姐弟大战调解现场", "e": "Case closed; court fees: you two **tidy** this floor together.", "z": "本案审结，诉讼费：你们俩一起把地板收拾了。"}, {"c": "亲子·姐弟大战调解现场", "e": "Ten minutes later they're allies again, plotting against **bedtime**.", "z": "十分钟后他们又结成同盟，密谋对抗睡觉时间。"}, {"c": "亲子·睡前流程标准版", "e": "Eight forty: the **bedtime train** leaves in twenty minutes.", "z": "八点四十：睡觉专列二十分钟后发车。"}, {"c": "亲子·睡前流程标准版", "e": "Toys clocked out, tomorrow's clothes **laid out** on the chair.", "z": "玩具下班，明天的衣服搭在椅子上。"}, {"c": "亲子·睡前流程标准版", "e": "Bath, pajamas, and the great nightly **tooth inspection**.", "z": "洗澡、睡衣，以及每晚一次的牙齿大检查。"}, {"c": "亲子·睡前流程标准版", "e": "Back teeth too — I can **hear** whether you really brushed.", "z": "后槽牙也要刷——你有没有认真刷我听得出来。"}, {"c": "亲子·睡前流程标准版", "e": "Hair dried fully; wet pillows breed **colds**.", "z": "头发彻底吹干，湿枕头是感冒的温床。"}, {"c": "亲子·睡前流程标准版", "e": "One glass of water now, so nobody's **thirsty** at ten thirty.", "z": "现在喝一杯水，省得十点半有人喊渴。"}, {"c": "亲子·睡前流程标准版", "e": "Tonight's story: chapter six, and only **one** chapter, we agreed.", "z": "今晚的故事：第六章，说好只讲一章。"}, {"c": "亲子·睡前流程标准版", "e": "Lights dimmed, voices soft — the whole flat shifts into **night mode**.", "z": "灯光调暗，声音放轻——整个家切换到夜间模式。"}, {"c": "亲子·睡前流程标准版", "e": "Tell me one thing you're **grateful** for today.", "z": "跟我说一件今天让你感恩的事。"}, {"c": "亲子·睡前流程标准版", "e": "He says the goal; she says the sticker; I say **you two**.", "z": "他说进球，她说贴纸，我说是你们俩。"}, {"c": "亲子·睡前流程标准版", "e": "Kisses on foreheads, curtains **drawn**, door left open a crack.", "z": "额头亲一下，窗帘拉好，门留一条缝。"}, {"c": "亲子·睡前流程标准版", "e": "Nine oh five: silence. The most beautiful **sound** in the house.", "z": "九点零五：安静了。全屋最动听的声音。"}, {"c": "亲子·夸孩子夸到点子上", "e": "Praise the **effort**, not just the score — that's my rule.", "z": "夸努力，不只夸分数——这是我的原则。"}, {"c": "亲子·夸孩子夸到点子上", "e": "I saw you check your answers **twice** — that's real discipline.", "z": "我看到你检查了两遍——这才叫自律。"}, {"c": "亲子·夸孩子夸到点子上", "e": "You didn't give up on that problem; you tried a **second way**.", "z": "那道题你没放弃，还换了第二种解法。"}, {"c": "亲子·夸孩子夸到点子上", "e": "Your handwriting today is **noticeably** neater than Monday's.", "z": "你今天的字比周一的明显工整。"}, {"c": "亲子·夸孩子夸到点子上", "e": "Thank you for helping your brother **without being asked**.", "z": "谢谢你不用提醒就去帮弟弟。"}, {"c": "亲子·夸孩子夸到点子上", "e": "That was a kind thing you did — kindness is a **strength**.", "z": "你刚才做的事很善良——善良是一种实力。"}, {"c": "亲子·夸孩子夸到点子上", "e": "You felt angry and you used **words** — I'm proud of that.", "z": "你很生气，但你选择了用语言表达——我为这个骄傲。"}, {"c": "亲子·夸孩子夸到点子上", "e": "You lost the game and still shook hands — that's **sportsmanship**.", "z": "你输了比赛还是握了手——这叫体育精神。"}, {"c": "亲子·夸孩子夸到点子上", "e": "I love how you asked that question; **curiosity** looks good on you.", "z": "我喜欢你问的那个问题——好奇心很配你。"}, {"c": "亲子·夸孩子夸到点子上", "e": "Be specific, be honest, and never compare them to the **neighbour's kid**.", "z": "要具体、要真诚，永远别拿别人家孩子作比较。"}, {"c": "亲子·夸孩子夸到点子上", "e": "A praised child doesn't get proud; a **seen** child gets confident.", "z": "被夸的孩子不会骄傲；被看见的孩子才会自信。"}, {"c": "亲子·夸孩子夸到点子上", "e": "Tonight's scorecard: two happy kids, one **hoarse** but happy mum.", "z": "今晚战绩：两个开心的娃，一个嗓子哑但快乐的妈。"}, {"c": "夫妻·晚归人的热饭协议", "e": "His message says **overtime** again; dinner shifts to plan B.", "z": "他发消息说又加班，晚饭切换 B 方案。"}, {"c": "夫妻·晚归人的热饭协议", "e": "I set aside a plate **before** we eat — untouched, best pieces on top.", "z": "开饭前我先留出一盘——没动过筷子的，好肉摆上层。"}, {"c": "夫妻·晚归人的热饭协议", "e": "The soup stays in the pot on the **lowest** flame, half-covered.", "z": "汤留在锅里，最小火半盖着焖。"}, {"c": "夫妻·晚归人的热饭协议", "e": "Nine ten: keys in the lock — the tired **footsteps** version.", "z": "九点十分：钥匙响了——是疲惫脚步声的版本。"}, {"c": "夫妻·晚归人的热饭协议", "e": "Sit, I'll **heat it up** — three minutes, not takeout, real food.", "z": "坐下吧，我热一下——三分钟，不是外卖，是真饭。"}, {"c": "夫妻·晚归人的热饭协议", "e": "He protests politely; I ignore him **professionally**.", "z": "他客气地推辞，我专业地无视。"}, {"c": "夫妻·晚归人的热饭协议", "e": "How was the meeting — the **short** version, you look drained.", "z": "会开得怎么样——讲个简短版就行，你看着被抽干了。"}, {"c": "夫妻·晚归人的热饭协议", "e": "I slide the chilli sauce over **before** he asks — twelve years of data.", "z": "不等他开口我就把辣酱推过去——十二年的大数据。"}, {"c": "夫妻·晚归人的热饭协议", "e": "The kids left you a drawing; it's you with a **superhero cape**.", "z": "孩子们给你留了幅画，画的是披着超人披风的你。"}, {"c": "夫妻·晚归人的热饭协议", "e": "Eat first, shower later, and the dishes are **mine** tonight.", "z": "先吃饭再洗澡，今晚的碗归我。"}, {"c": "夫妻·晚归人的热饭协议", "e": "He says thank you; I say **team**, not thank you.", "z": "他说谢谢；我说我们是一队的，不说谢。"}, {"c": "夫妻·晚归人的热饭协议", "e": "A warm plate at nine p.m. says more than a **long** speech.", "z": "晚上九点的一盘热饭，胜过千言万语。"}, {"c": "夫妻·周日分工圆桌会", "e": "Sunday, nine a.m.: the weekly **family logistics** meeting opens.", "z": "周日早九点：本周家庭后勤会议开幕。"}, {"c": "夫妻·周日分工圆桌会", "e": "Agenda on the fridge: meals, pickups, chores, and one **fun thing**.", "z": "议程贴冰箱上：三餐、接送、家务，外加一件乐事。"}, {"c": "夫妻·周日分工圆桌会", "e": "I cook weekdays; he takes the **weekend woks** — signed and sealed.", "z": "工作日我掌勺，周末锅铲归他——白纸黑字。"}, {"c": "夫妻·周日分工圆桌会", "e": "Tuesday's parent meeting is his; Thursday's **dentist** run is mine.", "z": "周二家长会他去，周四看牙医我带。"}, {"c": "夫妻·周日分工圆桌会", "e": "The tap still **drips**; he books a plumber before Wednesday.", "z": "水龙头还在滴，他周三前约好师傅。"}, {"c": "夫妻·周日分工圆桌会", "e": "I claim two hours on Saturday for my **English practice** — protected time.", "z": "我申请周六两小时练英语——神圣不可侵犯的时间。"}, {"c": "夫妻·周日分工圆桌会", "e": "He gets Sunday afternoon for **basketball** with his old classmates.", "z": "他获得周日下午和老同学打篮球的时间。"}, {"c": "夫妻·周日分工圆桌会", "e": "Grocery budget check: we **overspent** on fruit; worth it, we agree.", "z": "买菜预算盘点：水果超支了；我们一致认为值。"}, {"c": "夫妻·周日分工圆桌会", "e": "The kids get chores too: plants, **rubbish**, and setting the table.", "z": "孩子也有岗位：浇花、倒垃圾、摆碗筷。"}, {"c": "夫妻·周日分工圆桌会", "e": "Fun thing this week: a **night ride** along the river, all four of us.", "z": "本周乐事：全家四口夜骑江边。"}, {"c": "夫妻·周日分工圆桌会", "e": "Meeting closed in twenty minutes — our **record** is eleven.", "z": "会议二十分钟结束——我们的纪录是十一分钟。"}, {"c": "夫妻·周日分工圆桌会", "e": "A family runs on love, sure — and on a very clear **rota**.", "z": "家靠爱运转，没错——也靠一张清清楚楚的排班表。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "Saturday pilgrimage: dinner at the **in-laws'**, fruit basket in hand.", "z": "周六例行拜访：去公婆家吃饭，手里拎着果篮。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "Ma opens the door already **apologising** that there isn't much food.", "z": "婆婆一开门就先道歉说没做什么菜。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "There are, of course, **eight dishes** on the table.", "z": "当然，桌上摆着八个菜。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "I head straight to the kitchen: Ma, sit, I'll **plate up**.", "z": "我直奔厨房：妈您坐，我来装盘。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "Pa shows the kids his **chess set**; the annual lesson begins.", "z": "公公给孩子们摆开象棋，一年一度的教学开始。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "Ma's braised fish has a taste no **recipe** can teach.", "z": "婆婆的红烧鱼有一种菜谱教不会的味道。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "Eat more, she says, loading my bowl before I can **dodge**.", "z": "多吃点，她说着，不等我躲闪就往我碗里夹。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "We trade **health updates**: her knee, his blood pressure, our sleep.", "z": "我们互换健康情报：她的膝盖，他的血压，我们的睡眠。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "I mention the stairs; maybe it's time for the **ground-floor** flat idea.", "z": "我提了提爬楼的事，也许该考虑换一楼了。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "After dinner, the kids **perform** their new English show — a hit.", "z": "饭后孩子们表演新学的英语节目——大获成功。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "Ma packs us leftovers in **three** layers of boxes — resistance is futile.", "z": "婆婆用三层饭盒给我们打包剩菜——抵抗无效。"}, {"c": "长辈·去公婆家吃饭的一课", "e": "Family isn't a visit; it's a **habit** — see you next Saturday.", "z": "亲情不是一次拜访，是一种习惯——下周六见。"}, {"c": "长辈·给爸妈的例行视频", "e": "Eight p.m. sharp: the weekly **video call** to my parents connects.", "z": "晚八点整：给爸妈的每周视频准时接通。"}, {"c": "长辈·给爸妈的例行视频", "e": "The camera shows the **ceiling** first, as tradition demands.", "z": "镜头照例先对着天花板。"}, {"c": "长辈·给爸妈的例行视频", "e": "Ma, tilt the phone **down** a little — there you are!", "z": "妈，手机往下低一点——这就看见您啦！"}, {"c": "长辈·给爸妈的例行视频", "e": "The kids crowd in to show grandma their **missing tooth** news.", "z": "孩子们挤进镜头，向外婆汇报掉牙的最新进展。"}, {"c": "长辈·给爸妈的例行视频", "e": "Dad pretends he wasn't waiting by the phone — his **jacket** says otherwise.", "z": "爸假装没在电话边等——但他外套都穿好了，出卖了他。"}, {"c": "长辈·给爸妈的例行视频", "e": "Have you two been taking your **evening walks**? Show me steps!", "z": "你们俩晚上散步了吗？把步数亮出来看看！"}, {"c": "长辈·给爸妈的例行视频", "e": "Ma reports the **community clinic** trip: blood pressure, all normal.", "z": "妈汇报了社区医院之行：血压一切正常。"}, {"c": "长辈·给爸妈的例行视频", "e": "I remind Dad the **heater** filter needs changing before winter.", "z": "我提醒爸，入冬前要换取暖器的滤网。"}, {"c": "长辈·给爸妈的例行视频", "e": "They ask about my work with that **careful** lightness parents use.", "z": "他们用父母特有的小心翼翼，轻描淡写地问我工作。"}, {"c": "长辈·给爸妈的例行视频", "e": "We book the **train tickets** for their visit next month — done, no refunds!", "z": "我们把他们下个月来的火车票订了——订完，不许反悔！"}, {"c": "长辈·给爸妈的例行视频", "e": "Ma signs off with her eternal closer: eat properly, **wear more**.", "z": "妈用她永恒的结束语收尾：好好吃饭，多穿点。"}, {"c": "长辈·给爸妈的例行视频", "e": "Twenty minutes, two screens, one **whole** family.", "z": "二十分钟，两块屏幕，一个完整的家。"}, {"c": "外出·超市大采购动线", "e": "Saturday supermarket run: list in phone, **tote bags** in hand.", "z": "周六超市采购：清单在手机里，布袋拎手上。"}, {"c": "外出·超市大采购动线", "e": "Strategy: produce first, **frozen last** — melting is defeat.", "z": "路线战略：先生鲜，最后冷冻——化了就是败仗。"}, {"c": "外出·超市大采购动线", "e": "The trolley has a **rebel wheel**; we adopt it anyway.", "z": "购物车有个叛逆的轮子，我们照样收编它。"}, {"c": "外出·超市大采购动线", "e": "I compare unit prices on the **shelf labels**, not the big red signs.", "z": "我看货架标签上的单价，不看大红促销牌。"}, {"c": "外出·超市大采购动线", "e": "Buy-one-get-one on yogurt — check the **expiry date** first. It's fine.", "z": "酸奶买一送一——先看保质期，没问题。"}, {"c": "外出·超市大采购动线", "e": "The kids negotiate for **crisps**; approved, one bag, small size.", "z": "孩子们就薯片展开谈判；批准，一袋，小包装。"}, {"c": "外出·超市大采购动线", "e": "Eggs: I open the box and give each one a **wiggle** test.", "z": "鸡蛋：开盒逐个轻晃检查。"}, {"c": "外出·超市大采购动线", "e": "Free samples ahead — we taste, we smile, we **keep walking**.", "z": "前方有试吃——我们尝了，笑了，继续走。"}, {"c": "外出·超市大采购动线", "e": "Weigh the loose fruit **before** the checkout, sticker on the bag.", "z": "散装水果先称重贴签，再去结账。"}, {"c": "外出·超市大采购动线", "e": "Self-checkout, phone **QR** flash, receipt straight to email.", "z": "自助结账，手机二维码一闪，小票直接进邮箱。"}, {"c": "外出·超市大采购动线", "e": "Total: two hundred and six — under **budget** by four yuan. Victory.", "z": "总计二百零六——比预算省四块。胜利。"}, {"c": "外出·超市大采购动线", "e": "Home stretch: heavy bags, light heart, and ice cream **intact**.", "z": "最后一程：袋子沉，心情轻，冰淇淋完好无损。"}, {"c": "外出·快递驿站取件与退货", "e": "Three pickup codes today — the **express station** knows me by face.", "z": "今天三个取件码——驿站已经认得我这张脸了。"}, {"c": "外出·快递驿站取件与退货", "e": "Code one: shelf **B-twelve**, a box light as a feather.", "z": "第一个码：B12架，一个轻得像羽毛的箱子。"}, {"c": "外出·快递驿站取件与退货", "e": "Code two is the kids' **workbooks**; code three, a mystery from Dad.", "z": "第二个是孩子的练习册；第三个，是孩子他爸的神秘包裹。"}, {"c": "外出·快递驿站取件与退货", "e": "I scan out at the machine — it **beeps** approval, very satisfying.", "z": "出库机器上一扫——嘀一声放行，莫名解压。"}, {"c": "外出·快递驿站取件与退货", "e": "Now the return: these shoes run a **size small**.", "z": "接下来退货：这双鞋偏小一码。"}, {"c": "外出·快递驿站取件与退货", "e": "The app gives me a **return code**; original box, tags still on.", "z": "App生成退货码；原盒原标签都在。"}, {"c": "外出·快递驿站取件与退货", "e": "The clerk checks it, weighs it, and prints the **label** — one minute.", "z": "店员核对、称重、打单——一分钟搞定。"}, {"c": "外出·快递驿站取件与退货", "e": "Refund lands **before** I even reach the community gate. Modern life.", "z": "还没走到小区门口退款就到账了。这就是现代生活。"}, {"c": "外出·快递驿站取件与退货", "e": "A neighbour's parcel is misplaced; I help her **track** it on the app.", "z": "邻居的包裹被放错了，我帮她在App上查物流。"}, {"c": "外出·快递驿站取件与退货", "e": "Found — it's at the **other** station across the road. Crisis over.", "z": "找到了——在马路对面那家驿站。危机解除。"}, {"c": "外出·快递驿站取件与退货", "e": "Pro tip: photograph the parcel **before** opening anything fragile.", "z": "经验：易碎品拆箱前先拍照留证。"}, {"c": "外出·快递驿站取件与退货", "e": "Three in, one out, zero drama — **logistics** level: mum.", "z": "取三退一零纠纷——物流段位：妈妈级。"}, {"c": "外出·药店买药问明白", "e": "The pharmacy at the corner — green cross **glowing**, in we go.", "z": "街角药店——绿十字亮着，进。"}, {"c": "外出·药店买药问明白", "e": "The little one has a **stuffy nose** and a mild cough, no fever.", "z": "小的鼻塞、轻微咳嗽，不发烧。"}, {"c": "外出·药店买药问明白", "e": "Is this syrup suitable for a **six-year-old**? What's the dose?", "z": "这个糖浆六岁能喝吗？剂量是多少？"}, {"c": "外出·药店买药问明白", "e": "Twice a day after **meals**, five millilitres — I note it in my phone.", "z": "一天两次饭后，每次五毫升——我记进手机。"}, {"c": "外出·药店买药问明白", "e": "Any **conflict** with the vitamin D he takes daily?", "z": "和他每天吃的维生素D有没有冲突？"}, {"c": "外出·药店买药问明白", "e": "She's allergic to **penicillin** — I say it before anyone asks.", "z": "她对青霉素过敏——不等人问我先说明。"}, {"c": "外出·药店买药问明白", "e": "I grab band-aids, **fever patches**, and a new thermometer.", "z": "我顺手拿了创可贴、退热贴和一支新体温计。"}, {"c": "外出·药店买药问明白", "e": "Do you have the **children's** version of this? The adult one is too strong.", "z": "这个有儿童装吗？成人的太猛了。"}, {"c": "外出·药店买药问明白", "e": "Check the **expiry**: use within eighteen months, we're good.", "z": "看下有效期：十八个月内，没问题。"}, {"c": "外出·药店买药问明白", "e": "Medical insurance card **swiped**; the rest by phone.", "z": "医保卡一刷，剩下的手机支付。"}, {"c": "外出·药店买药问明白", "e": "The pharmacist adds: plenty of water, and **back here** if it worsens.", "z": "药师叮嘱：多喝水，加重了再过来。"}, {"c": "外出·药店买药问明白", "e": "Small bag, clear instructions, calm mum — **prepared** beats panicked.", "z": "小小一袋药，说明清清楚楚，妈妈稳如老狗——有备就不慌。"}, {"c": "外出·带娃看医生全流程", "e": "His forehead reads **thirty-eight five** — okay, we're going in.", "z": "他额温三十八度五——好，出发去医院。"}, {"c": "外出·带娃看医生全流程", "e": "I pack the **insurance card**, records book, water, and a spare mask.", "z": "我带上医保卡、病历本、水和备用口罩。"}, {"c": "外出·带娃看医生全流程", "e": "Registration on the app: **paediatrics**, number forty-two.", "z": "App上挂号：儿科，四十二号。"}, {"c": "外出·带娃看医生全流程", "e": "The triage nurse takes his **temperature** again and tags us green.", "z": "分诊护士再量一次体温，给我们分了绿色通道。"}, {"c": "外出·带娃看医生全流程", "e": "Waiting room survival kit: one **storybook**, zero screens.", "z": "候诊生存包：一本故事书，零屏幕。"}, {"c": "外出·带娃看医生全流程", "e": "Called in — I give the doctor the **timeline**: fever since last night.", "z": "叫号了——我向医生汇报时间线：昨晚开始发烧。"}, {"c": "外出·带娃看医生全流程", "e": "Appetite low, sleep okay, **no vomiting** — short and useful.", "z": "胃口差，睡眠还行，没有呕吐——简短且有用。"}, {"c": "外出·带娃看医生全流程", "e": "The doctor checks his **throat** — say ahh — a bit red, she says.", "z": "医生检查嗓子——啊——她说有点红。"}, {"c": "外出·带娃看医生全流程", "e": "Blood test first; brave boy earns a **cartoon plaster**.", "z": "先验个血；勇敢的男子汉赢得一枚卡通创可贴。"}, {"c": "外出·带娃看医生全流程", "e": "Diagnosis: a common **virus** — rest, fluids, medicine for the fever.", "z": "诊断：普通病毒感染——休息、补水、发烧就吃退烧药。"}, {"c": "外出·带娃看医生全流程", "e": "Pay and **collect the medicine** downstairs, window six.", "z": "楼下六号窗口缴费取药。"}, {"c": "外出·带娃看医生全流程", "e": "Home by noon; soup on the stove and a **certified** brave patient napping.", "z": "中午前到家；汤在炉上，认证勇敢的小病号已入睡。"}, {"c": "外出·理发店的亲子时光", "e": "Haircut day: one **trim** for me, one 'not too short!' for him.", "z": "理发日：我修一修，他要求「别剪太短！」。"}, {"c": "外出·理发店的亲子时光", "e": "The barber drapes the **cape** and the boy becomes a tiny ghost.", "z": "理发师围上围布，小孩瞬间变成一只小幽灵。"}, {"c": "外出·理发店的亲子时光", "e": "Just tidy the **fringe** and keep the top — school photo next week.", "z": "刘海修整齐，顶上保留——下周拍学籍照。"}, {"c": "外出·理发店的亲子时光", "e": "Clippers on the sides, **scissors** on top, please.", "z": "两边推子，上面用剪刀，麻烦了。"}, {"c": "外出·理发店的亲子时光", "e": "He watches the mirror like it's a **movie** about himself.", "z": "他盯着镜子看，像在看一部关于自己的电影。"}, {"c": "外出·理发店的亲子时光", "e": "Itchy neck alert — the brush and **talc** save the day.", "z": "脖子发痒警报——毛刷和爽身粉及时救场。"}, {"c": "外出·理发店的亲子时光", "e": "My turn: shoulder-length, layers, and **no** surprise bangs.", "z": "轮到我：及肩、打层次，拒绝惊喜刘海。"}, {"c": "外出·理发店的亲子时光", "e": "We skip the hard sell on the **membership card** — politely, twice.", "z": "会员卡推销我们礼貌地拒绝了——两次。"}, {"c": "外出·理发店的亲子时光", "e": "The blow-dry turns him into a **dandelion**; we both crack up.", "z": "吹风机把他吹成一朵蒲公英，我俩笑作一团。"}, {"c": "外出·理发店的亲子时光", "e": "Mirror check, back view via the **small mirror** — approved.", "z": "照镜子，小镜子看后脑——通过。"}, {"c": "外出·理发店的亲子时光", "e": "Scan to pay, and a **lollipop** materialises from the counter.", "z": "扫码付款，前台变出一根棒棒糖。"}, {"c": "外出·理发店的亲子时光", "e": "Two fresh haircuts, one sugar-powered walk home — **sharp** family.", "z": "两颗新发型，一路糖分驱动地走回家——精神！"}, {"c": "社交·电梯里的邻居寒暄", "e": "Lift doors open: it's the **third-floor** aunty with her poodle.", "z": "电梯门一开：是三楼阿姨和她的贵宾犬。"}, {"c": "社交·电梯里的邻居寒暄", "e": "Morning! Walking the **dog** so early — he's got a new haircut!", "z": "早呀！这么早遛狗——它剪了新造型呀！"}, {"c": "社交·电梯里的邻居寒暄", "e": "She asks if my kids are on **summer holiday** yet; two more weeks.", "z": "她问孩子们放暑假没；还有两周。"}, {"c": "社交·电梯里的邻居寒暄", "e": "The sixth-floor grandpa joins with his **birdcage** — full house.", "z": "六楼爷爷提着鸟笼也进来了——满员。"}, {"c": "社交·电梯里的邻居寒暄", "e": "We all agree the weather turned **muggy** overnight.", "z": "我们一致认为一夜之间变闷热了。"}, {"c": "社交·电梯里的邻居寒暄", "e": "Aunty tips me off: the fruit shop has cherries **on sale** today.", "z": "阿姨透露情报：水果店今天樱桃特价。"}, {"c": "社交·电梯里的邻居寒暄", "e": "Grandpa's myna bird says '**ni hao**' and steals the show.", "z": "爷爷的八哥说了声「你好」，全场焦点被它抢走。"}, {"c": "社交·电梯里的邻居寒暄", "e": "I mention our tap repair guy — **reliable** and fair, want his number?", "z": "我提到我们修水管的师傅——靠谱又实在，要电话吗？"}, {"c": "社交·电梯里的邻居寒暄", "e": "Someone's parcel is at the station — small **favours** keep floors friendly.", "z": "谁家的包裹到驿站了——小事互相搭把手，邻里就熟络。"}, {"c": "社交·电梯里的邻居寒暄", "e": "Reminder circulating: **power cut** Thursday morning, nine to eleven.", "z": "顺便互通消息：周四上午九到十一点停电。"}, {"c": "社交·电梯里的邻居寒暄", "e": "Ding — my floor; see you, take **care** in this heat!", "z": "叮——到我这层了；回见，大热天当心身体！"}, {"c": "社交·电梯里的邻居寒暄", "e": "Thirty seconds of small talk, a whole **neighbourhood** of goodwill.", "z": "三十秒的寒暄，攒下一整栋楼的善意。"}, {"c": "社交·家长群的一天", "e": "Seven a.m.: the class group already has **forty-two** messages.", "z": "早七点：班级群已经四十二条消息。"}, {"c": "社交·家长群的一天", "e": "The teacher posts today's **schedule**; I reply a clean 'Received, thanks!'", "z": "老师发了今日安排，我干净利落回一句「收到，谢谢！」"}, {"c": "社交·家长群的一天", "e": "A form needs filling by noon — I **submit** it before I forget.", "z": "有个表格中午前要填——趁没忘我立刻交了。"}, {"c": "社交·家长群的一天", "e": "Someone asks about the **school trip** fee; the answer is three messages up.", "z": "有人问春游费用；答案就在上面第三条。"}, {"c": "社交·家长群的一天", "e": "I resist the urge to say 'please **scroll up**' — inner peace.", "z": "我忍住了没说「请往上翻」——心如止水。"}, {"c": "社交·家长群的一天", "e": "Photo drop: the kids at the science fair — mine is the **blur** in row two.", "z": "照片来了：科技节现场——我家娃是第二排那个虚影。"}, {"c": "社交·家长群的一天", "e": "A parent offers **carpool** for Friday; I sign us up and offer next week.", "z": "有家长发起周五拼车；我报了名，并认领下周。"}, {"c": "社交·家长群的一天", "e": "Homework clarification: page **thirty-eight**, questions one to five only.", "z": "作业答疑：第三十八页，只做一到五题。"}, {"c": "社交·家长群的一天", "e": "The teacher praises three kids for **improved handwriting** — one is ours!", "z": "老师表扬三个书写进步的孩子——有一个是我家的！"}, {"c": "社交·家长群的一天", "e": "I thank her **privately**, not in the group — less noise, more sincerity.", "z": "我私信道谢，不刷群——少刷屏，多真诚。"}, {"c": "社交·家长群的一天", "e": "Nine p.m.: group set to **mute**; tomorrow it all begins again.", "z": "晚九点：群消息设为免打扰；明天一切重来。"}, {"c": "社交·家长群的一天", "e": "Rule of the group: reply fast, ask **precisely**, never argue publicly.", "z": "混群法则：回复要快，提问要准，永远不公开抬杠。"}, {"c": "社交·家里来客人的下午", "e": "Guests at four — the flat gets its **fifteen-minute** miracle clean.", "z": "客人四点到——全屋进入十五分钟奇迹式打扫。"}, {"c": "社交·家里来客人的下午", "e": "The good **tea set** comes down from the top shelf, rinsed twice.", "z": "好茶具从顶柜请下来，烫洗两遍。"}, {"c": "社交·家里来客人的下午", "e": "Fruit plate, melon seeds, and the **walnuts** Dad cracks too loudly.", "z": "果盘、瓜子，还有孩子他爸嗑得震天响的核桃。"}, {"c": "社交·家里来客人的下午", "e": "Doorbell! Coats taken, **slippers** offered — the guest pair, the new ones.", "z": "门铃响！接外套，递拖鞋——客用的那双新的。"}, {"c": "社交·家里来客人的下午", "e": "Sit, sit — what tea do you drink? We have green, black, and **chrysanthemum**.", "z": "坐坐坐——喝什么茶？绿茶、红茶、菊花茶都有。"}, {"c": "社交·家里来客人的下午", "e": "The kids surface, greet everyone **by name**, then vanish with the cousins.", "z": "孩子们冒出来，逐一称呼问好，然后和表姐妹们消失了。"}, {"c": "社交·家里来客人的下午", "e": "Try the pomelo — sweet, and I'll **peel** more, it's no trouble.", "z": "尝尝柚子——很甜，我再剥一个，不麻烦。"}, {"c": "社交·家里来客人的下午", "e": "We catch up on jobs, schools, and everyone's **knees** — the aunt trilogy.", "z": "我们聊工作、聊上学、聊各自的膝盖——阿姨三部曲。"}, {"c": "社交·家里来客人的下午", "e": "Stay for dinner — the pot is **already on**, refusing is useless.", "z": "留下吃饭——锅已经坐上了，推辞无效。"}, {"c": "社交·家里来客人的下午", "e": "At the door, the gift **tug-of-war**: take it — no — take it — okay.", "z": "门口上演礼物拉锯战：拿着——不行——拿着——好吧。"}, {"c": "社交·家里来客人的下午", "e": "We walk them to the **lift** and wave until the doors close.", "z": "我们送到电梯口，挥手直到门合上。"}, {"c": "社交·家里来客人的下午", "e": "A full teapot, a loud flat, a sweet **exhaustion** — hosting, done right.", "z": "一壶见底的茶，一屋热闹，一种甜甜的疲惫——待客，就该这样。"}, {"c": "自我·我的英语晨读十五分钟", "e": "Six forty-five: kettle on, and my **English corner** opens for business.", "z": "六点四十五：水壶烧上，我的英语角开张。"}, {"c": "自我·我的英语晨读十五分钟", "e": "Phone on **airplane mode** — this quarter hour belongs to me.", "z": "手机开飞行模式——这一刻钟属于我自己。"}, {"c": "自我·我的英语晨读十五分钟", "e": "I read yesterday's ten sentences **aloud**, louder than feels polite.", "z": "昨天的十个句子大声朗读，声音大到有点不好意思。"}, {"c": "自我·我的英语晨读十五分钟", "e": "Tongue twisters first to wake up my **mouth muscles**.", "z": "先来绕口令，唤醒嘴部肌肉。"}, {"c": "自我·我的英语晨读十五分钟", "e": "New sentence today: I **shadow** the audio half a beat behind.", "z": "今天的新句子：我跟在音频后面半拍影子跟读。"}, {"c": "自我·我的英语晨读十五分钟", "e": "The word 'colleague' fights me; I repeat it **ten times**, slower.", "z": "colleague 这个词跟我作对；我放慢重复十遍。"}, {"c": "自我·我的英语晨读十五分钟", "e": "I record myself and **compare** — cringe first, improve second.", "z": "我录下自己再对比——先尴尬，后进步。"}, {"c": "自我·我的英语晨读十五分钟", "e": "Three sentences get promoted to my **use-today** list.", "z": "三个句子晋升进「今天就用」清单。"}, {"c": "自我·我的英语晨读十五分钟", "e": "At breakfast I'll test one on the kids — they're strict **judges**.", "z": "早餐时拿一句考验孩子们——他们是严格的评委。"}, {"c": "自我·我的英语晨读十五分钟", "e": "Small goal: one voice message in English to my **study group**.", "z": "小目标：给学习群发一条英语语音。"}, {"c": "自我·我的英语晨读十五分钟", "e": "Fifteen minutes, no miracles, just **bricks** — day forty-one.", "z": "十五分钟，没有奇迹，只有砖块——第四十一天。"}, {"c": "自我·我的英语晨读十五分钟", "e": "The kettle clicks; class **dismissed**, life resumes.", "z": "水壶跳闸；下课，生活继续。"}, {"c": "自我·睡前复盘五分钟", "e": "Ten twenty: house asleep, and I steal **five minutes** for myself.", "z": "十点二十：全家入睡，我偷出五分钟给自己。"}, {"c": "自我·睡前复盘五分钟", "e": "Three questions, same every night — my little **ritual**.", "z": "三个问题，每晚一样——我的小仪式。"}, {"c": "自我·睡前复盘五分钟", "e": "One: what did I **handle well** today? The sibling war, definitely.", "z": "第一：今天什么处理得好？绝对是姐弟大战调解。"}, {"c": "自我·睡前复盘五分钟", "e": "Two: what would I **redo**? I snapped at the slow lift. Petty.", "z": "第二：什么想重来？我冲慢吞吞的电梯发了火。小气了。"}, {"c": "自我·睡前复盘五分钟", "e": "Three: what am I **grateful** for? Hot soup and two loud kids.", "z": "第三：感恩什么？热汤，和两个吵吵闹闹的孩子。"}, {"c": "自我·睡前复盘五分钟", "e": "I jot tomorrow's top three on a **sticky note** — brain now off duty.", "z": "明天最重要的三件事写上便利贴——大脑正式下班。"}, {"c": "自我·睡前复盘五分钟", "e": "English check-in: I used four new **sentences** today. Streak alive.", "z": "英语打卡：今天用了四个新句子。连续纪录保住了。"}, {"c": "自我·睡前复盘五分钟", "e": "One page of my book — okay, three pages, it got **good**.", "z": "读一页书——好吧，三页，情节上头了。"}, {"c": "自我·睡前复盘五分钟", "e": "Phone charges **outside** the bedroom; we broke up at night, it and I.", "z": "手机在卧室外充电；晚上我和它分居了。"}, {"c": "自我·睡前复盘五分钟", "e": "Lights out, and I hear the fridge **hum** its one-note lullaby.", "z": "关灯，听见冰箱哼着它单音节的摇篮曲。"}, {"c": "自我·睡前复盘五分钟", "e": "Not a perfect day — a **real** one, and that's better.", "z": "不是完美的一天——是真实的一天，这更好。"}, {"c": "自我·睡前复盘五分钟", "e": "Tomorrow, we go **again** — softer, smarter, still smiling.", "z": "明天，继续——更温柔、更聪明、依然微笑。"}];
